# Python-like pseudocode for Natural Join
# Tables represented as lists of dictionaries

chapters = [
    {'ChapterID': 1, 'ChapterTitle': 'Introduction', 'Pages': 25, 'BookID': 101},
    {'ChapterID': 2, 'ChapterTitle': 'Data Models', 'Pages': 40, 'BookID': 101},
    {'ChapterID': 3, 'ChapterTitle': 'SQL Basics', 'Pages': 35, 'BookID': 102}
]

books = [
    {'BookID': 101, 'Title': 'Database Systems', 'Author': 'Chen'},
    {'BookID': 102, 'Title': 'SQL Guide', 'Author': 'Smith'}
]

def natural_join(R, S, common_attrs):
    result = []
    for t1 in R:
        for t2 in S:
            match = True
            for attr in common_attrs:
                if t1[attr] != t2[attr]:
                    match = False
                    break
            if match:
                merged = {**t1, **t2}
                result.append(merged)
    return result

# Execute: Join chapters with books on BookID
joined_result = natural_join(chapters, books, ['BookID'])
# Output: Combined chapter and book information
